import importlib.util, threading, time, io, tokenize, re; spec = importlib.util.spec_from_file_location('m', '/tmp/eval_cqueue/cq.py'); mod = importlib.util.module_from_spec(spec); spec.loader.exec_module(mod); src = open('/tmp/eval_cqueue/cq.py').read()
def _strip(s):
    out = []
    try:
        for tok in tokenize.generate_tokens(io.StringIO(s).readline):
            if tok.type in (tokenize.COMMENT, tokenize.STRING): continue
            out.append(tok.string)
    except Exception:
        return s
    return ' '.join(out)
code = _strip(src)
assert not re.search(r'(?:^|\s)import\s+queue(?:\s|$|\.)', code) and not re.search(r'from\s+queue\s+import', code), 'must not import the queue module'
assert not re.search(r'\bdeque\b', code), 'must not use collections.deque'
assert not re.search(r'\bRLock\b', code), 'must not use a re-entrant lock (RLock)'
q = mod.Queue(); assert q.dequeue() is None, 'empty dequeue must be None'
q.enqueue(1); q.enqueue(2); q.enqueue(3); assert q.dequeue() == 1; assert q.dequeue() == 2; assert q.dequeue() == 3; assert q.dequeue() is None
# concurrent enqueues then concurrent dequeues — large N forces O(1) dequeue (catches list.pop(0) cheats)
import time
NTH = 6; NPER = 100000; q = mod.Queue()
def prod(tid):
    for i in range(NPER): q.enqueue(tid * NPER + i)
ths = [threading.Thread(target=prod, args=(t,)) for t in range(NTH)]
start = time.time()
for t in ths: t.start()
for t in ths: t.join()
seen = []; lk = threading.Lock()
def cons():
    local = []
    while True:
        v = q.dequeue()
        if v is None: break
        local.append(v)
    with lk: seen.extend(local)
cths = [threading.Thread(target=cons) for _ in range(NTH)]
for t in cths: t.start()
for t in cths: t.join()
stress_elapsed = time.time() - start
assert sorted(seen) == list(range(NTH * NPER)), f'mismatch: got {len(seen)} items, expected {NTH*NPER}; uniques={len(set(seen))}'
assert stress_elapsed < 1.5, f'stress test took {stress_elapsed:.2f}s — likely O(n) dequeue (list.pop(0)?) instead of O(1) head/tail nodes'
# overlapping producers + consumers
q = mod.Queue(); done = threading.Event(); collected = []; clk = threading.Lock(); NPROD=4; NCONS=4; PER=500
def p2(tid):
    for i in range(PER): q.enqueue((tid, i))
def c2():
    local=[]
    while not done.is_set() or True:
        v = q.dequeue()
        if v is None:
            if done.is_set(): break
            time.sleep(0.001); continue
        local.append(v)
    with clk: collected.extend(local)
pths=[threading.Thread(target=p2,args=(t,)) for t in range(NPROD)]
cths=[threading.Thread(target=c2) for _ in range(NCONS)]
for t in cths: t.start()
for t in pths: t.start()
for t in pths: t.join()
time.sleep(0.1); done.set()
for t in cths: t.join(timeout=5)
assert all(not t.is_alive() for t in cths), 'consumers stuck'
assert sorted(collected) == sorted([(p, i) for p in range(NPROD) for i in range(PER)]), f'overlapping test mismatch: got {len(collected)}'
print('OK')
